mapper.select:
SELECT A.comp_id, A.write_year, A.doc_type, A.doc_no, A.orgn_id, (SELECT ORGN.orgn_nm FROM esg.tb_orgn_info ORGN WHERE A.comp_id = ORGN.comp_id AND A.orgn_id = ORGN.orgn_id) AS orgn_nm, A.use_yn, A.created_at, COUNT(DISTINCT B.doc_seq) AS riskDetailCount, COUNT(DISTINCT C.doc_seq) AS oppDetailCount, COUNT(DISTINCT D.doc_seq) AS parDetailCount, (CASE WHEN G.signature IS NOT NULL THEN 'Y' WHEN F.signature IS NOT NULL THEN 'I' WHEN E.signature IS NOT NULL THEN 'W' ELSE 'C' END) AS approval_status FROM esg.tb_risks_and_opportunities A LEFT JOIN esg.tb_risks_and_opportunities_risk_detail B ON A.write_year = B.write_year AND A.doc_type = B.doc_type AND A.doc_no = B.doc_no AND B.use_yn = 'Y' LEFT JOIN esg.tb_risks_and_opportunities_opp_detail C ON A.write_year = C.write_year AND A.doc_type = C.doc_type AND A.doc_no = C.doc_no AND C.use_yn = 'Y' LEFT JOIN esg.tb_risks_and_opportunities_par_detail D ON A.write_year = D.write_year AND A.doc_type = D.doc_type AND A.doc_no = D.doc_no AND D.use_yn = 'Y' LEFT JOIN esg.tb_approval_info E ON E.target_type = A.doc_type AND E.target_id = A.write_year || A.doc_no AND E.param = 'writer' LEFT JOIN esg.tb_approval_info F ON F.target_type = A.doc_type AND F.target_id = A.write_year || A.doc_no AND F.param = 'reviewer' LEFT JOIN esg.tb_approval_info G ON G.target_type = A.doc_type AND G.target_id = A.write_year || A.doc_no AND G.param = 'approver' WHERE A.comp_id = #{compId}
AND A.write_year = #{writeYear}
AND A.doc_type = #{docType}
AND A.doc_no = #{docNo}
GROUP BY A.comp_id, A.write_year, A.doc_type, A.doc_no, A.orgn_id, A.use_yn, A.created_at, E.signature, F.signature, G.signature ORDER BY A.WRITE_YEAR DESC

mapper.update:
   		UPDATE esg.tb_risks_and_opportunities
       	   SET use_yn = #{useYn},
       	   	   updated_at = now(),
	           updated_by = #{updatedBy}
         WHERE write_year = #{writeYear}
           AND doc_type = #{docType}
           AND doc_no = #{docNo}

   		UPDATE esg.tb_risks_and_opportunities_par_detail
       	   SET duties = #{duties},
			   hr_id = #{hrId},
			   use_yn = #{parUseYn},
       	   	   updated_at = now(),
	           updated_by = #{updatedBy}
         WHERE write_year = #{writeYear}
           AND doc_type = #{docType}
           AND doc_no = #{docNo}
           AND doc_seq = #{parDocSeq}

